const i18n={en:{loading:'Loading',navServices:'Services',navPortfolio:'Portfolio',navContact:'Contact',navHire:'Hire Me',heroBadge:'Available for freelance projects',heroName:'Yahya Reda',heroTitle1:'Freelance',heroTitle2:'Web Developer',heroSub:'I build high-converting modern websites that bring clients and sales — not just pretty pages.',heroCta1:'Hire Me Now',heroCta2:'View My Work',trust1:'Fast Delivery',trust2:'Responsive Design',trust3:'Clean Code',codeComment:'build a site that sells',codeH1:'High-Converting Websites',codeP:'Built to turn visitors into clients.',codeCta:'Hire Me',codeFn:'results-driven development',problemTitle:'The Problem',problemDesc:"Most websites don't convert visitors into customers. A slow, messy design costs you real sales every single day.",solutionTitle:'The Solution',solutionDesc:'I build landing pages that sell for you 24/7 — fast, responsive, and built to turn traffic into paying clients.',stat1:'Projects Delivered',stat2:'Happy Clients',stat3:'Years Experience',stat4:'% Client Satisfaction',servicesLabel:'What I Do',servicesTitle:'Services',servicesSub:'Every website I build is crafted for speed, conversions, and a premium user experience.',svc1Title:'Landing Page Design',svc1Desc:'High-converting single-page sites built to capture leads and drive action from the first scroll.',svc2Title:'Full Website Development',svc2Desc:'Multi-page, fully responsive websites tailored to your business goals and brand identity.',svc3Title:'Portfolio Websites',svc3Desc:'Showcase your work with a clean, modern portfolio that impresses clients and gets you hired.',svc4Title:'Business Websites',svc4Desc:'Professional business sites that build trust, showcase services, and convert visitors into leads.',skillsLabel:'Tech Stack',skillsTitle:'Skills & Tools',skillsSub:'Modern technologies I use to build fast, reliable, and scalable websites.',testLabel:'Client Feedback',testTitle:'What Clients Say',testSub:"Real feedback from people I've worked with.",test1Text:'"Yahya built our company website from scratch. The design was exactly what we wanted and the turnaround was incredibly fast."',test1Author:'Ahmed M.',test1Role:'Founder, TechStart',test2Text:'"Professional, responsive, and the code is super clean. My site loads in under 2 seconds now. Highly recommended."',test2Author:'Sara K.',test2Role:'Business Owner',test3Text:'"Yahya redesigned my portfolio and I started getting client inquiries within a week. The modern look made all the difference."',test3Author:'Omar L.',test3Role:'Freelance Designer',portLabel:'Recent Work',portTitle:'Portfolio',portSub:"Real projects I've built. Each one focused on delivering results.",portTag1:'Web App',portTag2:'Web App',portBtn:'View Project',portDesc1:'A fitness coaching platform built with a modern, conversion-optimized design.',portDesc2:'An online bookstore with a seamless shopping experience. Clean design, fast browsing.',whyLabel:'Why Work With Me',whyTitle:'Built for Results',whySub:'I treat every project like a business investment — not just a code task.',why1Title:'Fast Delivery',why1Desc:"I respect your time and deliver ahead of schedule without cutting corners.",why2Title:'Modern UI/UX Design',why2Desc:'Clean, conversion-focused design that looks premium on every screen size.',why3Title:'Responsive on All Devices',why3Desc:'Mobile-first layouts that look flawless on phones, tablets, and desktops.',why4Title:'Clean Optimized Code',why4Desc:'Well-structured, performant code that loads fast and is easy to maintain.',why5Title:'Freelancer-Focused Communication',why5Desc:"Clear, honest communication with no jargon — you'll always know what's happening.",ctaTitle:'Ready to turn your idea into a real website?',ctaDesc:"Let's build something that works for your business. No fluff, just results.",ctaBtn:'Start Your Project',faqLabel:'Questions',faqTitle:'Frequently Asked',faqSub:'Everything you need to know before starting.',faq1q:'How long does a project typically take?',faq1a:'A single landing page takes 3-5 days. A multi-page website takes 7-10 days. Complex projects are scoped together based on your needs.',faq2q:'What do you need from me to get started?',faq2a:"Just your idea, brand colors/styles if you have them, and any content/text you want on the site. I'll guide you through the rest.",faq3q:'Do you offer revisions after delivery?',faq3a:"Yes! Each plan includes revision rounds. I make sure you're 100% happy before we finish.",faq4q:'Do you handle hosting and domain setup?',faq4a:"Absolutely. I can help you with hosting setup, domain configuration, and deployment. I'll make sure your site is live and working smoothly.",contactLabel:'Get In Touch',contactTitle:"Let's Build Something Great",contactSub:"Tell me about your project and I'll get back to you within 24 hours.",formName:'Your Name',formEmail:'Your Email',formMsg:'Tell me about your project...',formBtn:'Send Message',contactTalk:"Let's Talk",contactTalkDesc:"Prefer instant messaging? Reach out directly and I'll respond quickly.",instagram:'Instagram – @idk_yahia_',whatsapp:'WhatsApp – +20 122 876 8422',footerName:'Yahya Reda',footerTag:'Built to convert.'},ar:{loading:'بس كده...',navServices:'الخدمات',navPortfolio:'شغلي',navContact:'كلمني',navHire:'وظفني',heroBadge:'متاح دلوقتي — 📍',heroName:'يحيى رضا',heroTitle1:'فريلانسر',heroTitle2:'مطور ويب',heroSub:'بعمل مواقع ويب عصرية بتجيبلك عُملاء ومبيعات — مش مجرد وشوش حلوة.',heroCta1:'وظفني بقي',heroCta2:'شوف شغلي',trust1:'تسليم قبل المعاد',trust2:'شغال على الموبايل',trust3:'كود نضيف',codeComment:'ابني موقع يبيع',codeH1:'مواقع عالية التحويل',codeP:'مصممة تحوّل الزوار لعملاء.',codeCta:'كلمني',codeFn:'تطوير بالنتيجة مش بالكلام',problemTitle:'المشكلة',problemDesc:'المواقع التقليدية مبتحوّش زوار لعملاء. تصميم بطيء ومش مرتب؟ ده بيكلفك فلوس كل يوم.',solutionTitle:'الحل',solutionDesc:'بعمل صفحات هبوط تبيعلك 24/7 — سريعة ومتجاوبة ومصممة تحوّل الزوار لفلوس.',stat1:'مشروع وخلاص',stat2:'عميل مبسوط',stat3:'سنين خبرة',stat4:'% رضا',servicesLabel:'بعمل إيه',servicesTitle:'الخدمات',servicesSub:'كل موقع بشيل همّه — سرعة، تحويل، وشكل يجنّن.',svc1Title:'صفحات هبوط',svc1Desc:'صفحة واحدة بس، ولكنها بتجيبلك عُملاء. مصممة تقنع الزوّار ياخدوا الخطوة من أول سكرول.',svc2Title:'مواقع كاملة',svc2Desc:'مواقع بصفحات كتير وكلها متجاوبة — حسب أهداف شغلك وذوقك.',svc3Title:'بورتفوليو شخصي',svc3Desc:'اعرض شغلك بشكل نضيف وعصري يخلي العميل يقول "أنا عايز ده".',svc4Title:'مواقع تجارية',svc4Desc:'موقع لشركتك يبني ثقة ويعرض خدماتك ويحوّل الزوار لعملاء بيزنس.',skillsLabel:'التقنيات',skillsTitle:'المهارات والأدوات',skillsSub:'أحدث التقنيات اللي بشتغل بيها عشان أبنّي مواقع سريعة ومتينة.',testLabel:'الناس رأيها إيه',testTitle:'اللي اشتغلوا معاي',testSub:'كلام حقيقي من ناس شغلت معاهم.',test1Text:'"يحيى عمل موقع الشركة من الصفر. التصميم طلع زي الفل والتسليم كان أسرع من المتوقع."',test1Author:'أحمد م.',test1Role:'مؤسس TechStart',test2Text:'"محترف وموهوب والكود بتاعه نضيف. موقعي بقى يحمّل في أقل من 2 ثانية. أنصح بيه."',test2Author:'سارة ك.',test2Role:'صاحبة بيزنس',test3Text:'"يحيى عمّل لي البورتفوليو بتاعي من جديد وأنا بدأت أجيلنا عُملاء في أسبوع! الشكل العصري فرق جداً."',test3Author:'عمر ل.',test3Role:'مصمم فريلانسر',portLabel:'آخر شغل',portTitle:'شغلي',portSub:'مشاريع حقيقية بنيتها — كل واحد فيهم عشان يجيب نتيحة.',portTag1:'تطبيق ويب',portTag2:'تطبيق ويب',portBtn:'شوف المشروع',portDesc1:'منصة كوتشينج لياقة بدنية — تصميم عصري ومحسّن للتحويل يجيب مشتركين.',portDesc2:'متجر كتب أونلاين — تجربة تسوق زي الفل، تصميم نضيف، وتصفح سريع.',whyLabel:'ليه أنا بالذات؟',whyTitle:'عشان بتعب في شغلك',whySub:'بعتبر كل مشروع هو مشروعي أنا شخصياً — مش مجرد كود بكتبه.',why1Title:'أسلم قبل المعاد',why1Desc:'باحترم وقتك وأسلّم الشغل قبل ما تتوقعه — من غير ما أتعب في الجودة طبعاً.',why2Title:'تصميم يجنّن',why2Desc:'تصميم نضيف يركز على إنه يحوّل الزوار لعملاء ويشكّل على كل الأجهزة.',why3Title:'شغال على الموبايل والتاب',why3Desc:'أوّل ما أبدأ بفكّر في الموبايل — عشان كل الناس بتتصفح من تليفونها دلوقتي.',why4Title:'كود نضيف وصريح',why4Desc:'كود منظم وسريع — يتحمّل بسرعة ويبقى سهل لو عاوز تزود فيه بعدين.',why5Title:'كلام مصري صريح',why5Desc:'بتكلم معاك في الصَريح — من غير لف ودوران. هتعرف بالظبط إيه اللي بيحصل في مشروعك.',ctaTitle:'جهّزت فكرة وعايز موقع حقيقي؟',ctaDesc:'يلا نعمل حاجة تشتغل وتجيبلك فلوس. من غير هزار — ولا كلام فاضي.',ctaBtn:'ابدأ مشروعك',faqLabel:'أسئلة',faqTitle:'أسئلة بتتكرر',faqSub:'كل حاجة عاوز تعرفها قبل ما نبدأ.',faq1q:'المشروع بياخد قد إيه؟',faq1a:'صفحة هبوط واحدة: 3-5 أيام. موقع بصفحات: 7-10 أيام.',faq2q:'عاوز إيه منّي عشان نبدأ؟',faq2a:'فقط فكرتك وألوانك لو موجودة. وأي محتوى عايز تحطّه. والباقي أنا معاك فيه.',faq3q:'لو عاوز تغييرات بعد التسليم؟',faq3a:'أكيد فيه تعديلات. أنا مش بسلّم إلا وأنت مبسوط 100%.',faq4q:'الاستضافة والدومين مين بيعملهم؟',faq4a:'أنا معاك في الخطوة دي برضه. بهيّئلك الاستضافة والدومين وأخلّي موقعك شغال وسليم.',contactLabel:'كلمني',contactTitle:'يلا نعمل حاجة حلوة سوا',contactSub:'احكيلي عن مشروعك وهرد عليك في أقل من 24 ساعة — أَصْدق.',formName:'اسمك',formEmail:'إيميلك',formMsg:'احكيلي عن مشروعك...',formBtn:'ابعت',contactTalk:'كلمني',contactTalkDesc:'عاوز تكلم دلوقتي؟ ابعت على الواتساب أو تعالا انستغرام، هرد بسرعة.',instagram:'إنستغرام – @idk_yahia_',whatsapp:'واتساب – +20 122 876 8422',footerName:'يحيى رضا',footerTag:'شغال عشانك.'}};let currentLang=localStorage.getItem('lang')||'en';function applyTranslation(lang){const t=i18n[lang];document.documentElement.lang=lang==='ar'?'ar':'en';document.documentElement.dir=lang==='ar'?'rtl':'ltr';document.body.setAttribute('lang',lang);document.querySelectorAll('[data-i18n]').forEach(el=>{const key=el.dataset.i18n;if(t[key]){el.textContent=t[key]}});document.querySelectorAll('[data-i18n-placeholder]').forEach(el=>{const key=el.dataset.i18nPlaceholder;if(t[key])el.placeholder=t[key]});document.getElementById('langLabel').textContent=lang==='en'?'AR':'EN';if(lang==='ar'&&typewriterEl&&!typewriterDone){typewriterDone=true;typewriterEl.innerHTML='<span>'+t.heroSub+'</span><span class="cursor">|</span>'}}const typewriterEl=document.getElementById('typewriter');let typewriterDone=false;function startTypewriter(lang){const text=i18n[lang].heroSub;if(typewriterDone)return;typewriterDone=true;typewriterEl.innerHTML='<span></span><span class="cursor">|</span>';const span=typewriterEl.querySelector('span');let i=0;function type(){if(i<text.length){span.textContent+=text.charAt(i);i++;setTimeout(type,28+Math.random()*20)}}setTimeout(type,400)}applyTranslation(currentLang);startTypewriter(currentLang);function hideLoader(){const l=document.getElementById('loader');if(l)l.classList.add('hide');document.body.classList.add('loaded')}window.addEventListener('load',()=>{try{AOS.init({duration:1000,once:true,offset:100,easing:'ease-out-cubic',disable:window.innerWidth<768?'mobile':false})}catch(e){}setTimeout(hideLoader,600)});setTimeout(hideLoader,2000);document.getElementById('langToggle').addEventListener('click',()=>{currentLang=currentLang==='en'?'ar':'en';localStorage.setItem('lang',currentLang);applyTranslation(currentLang);if(currentLang==='ar'){typewriterDone=false;startTypewriter('ar')}});const toggle=document.getElementById('menuToggle');const navLinks=document.getElementById('navLinks');toggle.addEventListener('click',()=>{navLinks.classList.toggle('open');toggle.classList.toggle('open')});navLinks.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{navLinks.classList.remove('open');toggle.classList.remove('open')})});const sections=document.querySelectorAll('section[id]');const navLinkEls=document.querySelectorAll('.nav-link');window.addEventListener('scroll',()=>{let current='';sections.forEach(s=>{const top=s.offsetTop-200;if(window.pageYOffset>=top)current=s.getAttribute('id')});navLinkEls.forEach(a=>{a.classList.toggle('active',a.getAttribute('href')==='#'+current)})});const nav=document.querySelector('nav');window.addEventListener('scroll',()=>{nav.classList.toggle('scrolled',window.pageYOffset>60)});let counted=false;const statObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting&&!counted){counted=true;document.querySelectorAll('.stat-number').forEach(el=>{const target=parseInt(el.dataset.count);const duration=1500;const start=performance.now();function update(now){const progress=Math.min((now-start)/duration,1);const eased=1-Math.pow(1-progress,3);const suffix=el.dataset.count==='98'?'%':'+';el.textContent=Math.floor(eased*target)+suffix;if(progress<1)requestAnimationFrame(update)}requestAnimationFrame(update)})}})},{threshold:0.4});const statsEl=document.querySelector('#stats .stats-grid');if(statsEl)statObserver.observe(statsEl);const form=document.getElementById('contactForm');const feedback=document.getElementById('formFeedback');form.addEventListener('submit',async(e)=>{e.preventDefault();const name=form.name.value.trim();const email=form.email.value.trim();const message=form.message.value.trim();let valid=true;[form.name,form.email,form.message].forEach(f=>f.classList.remove('error'));if(!name){form.name.classList.add('error');valid=false}if(!email||!email.includes('@')){form.email.classList.add('error');valid=false}if(!message){form.message.classList.add('error');valid=false}if(!valid){feedback.className='form-feedback error show';feedback.textContent=currentLang==='ar'?'يا باشا، إملى كل الحقول الأول 😅':'Please fill in all fields correctly.';return}try{const csrfToken=document.querySelector('meta[name="csrf-token"]').getAttribute('content');const res=await fetch('/api/contact',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,email,message,_csrf:csrfToken})});const data=await res.json();if(data.success){feedback.className='form-feedback success show';feedback.textContent=currentLang==='ar'?'تسلم يا '+name+'! رسالتك وصلت، هرد عليك في أسرع وقت 💪':'Thanks, '+name+'! Your message has been sent.';form.reset()}else{feedback.className='form-feedback error show';feedback.textContent=data.error||'Something went wrong.'}}catch(err){feedback.className='form-feedback error show';feedback.textContent=currentLang==='ar'?'حصل خطأ، حاول تاني.':'An error occurred. Please try again.'}setTimeout(()=>feedback.classList.remove('show'),5000)});document.querySelectorAll('.faq-q').forEach(btn=>{btn.addEventListener('click',()=>{const item=btn.parentElement;const isActive=item.classList.contains('active');document.querySelectorAll('.faq-item').forEach(i=>i.classList.remove('active'));if(!isActive)item.classList.add('active')})});const backBtn=document.getElementById('backToTop');window.addEventListener('scroll',()=>{backBtn.classList.toggle('visible',window.pageYOffset>500)});backBtn.addEventListener('click',()=>{window.scrollTo({top:0,behavior:'smooth'})});const glow=document.getElementById('mouseGlow');if(window.matchMedia('(hover: hover)').matches){document.addEventListener('mousemove',(e)=>{glow.style.transform='translate('+(e.clientX-200)+'px, '+(e.clientY-200)+'px)'})};if(window.innerWidth>768){document.querySelectorAll('.service-card,.portfolio-card').forEach(c=>{c.addEventListener('mousemove',e=>{const r=c.getBoundingClientRect();const x=e.clientX-r.left-r.width/2;const y=e.clientY-r.top-r.height/2;c.style.transform=`translateY(-10px) scale(1.03) perspective(600px) rotateX(${-y/20}deg) rotateY(${x/20}deg)`});c.addEventListener('mouseleave',()=>{c.style.transform=''})})};window.addEventListener('scroll',()=>{const hero=document.getElementById('hero');if(!hero)return;const rect=hero.getBoundingClientRect();const scrolled=Math.max(0,Math.min(1,(window.innerHeight-rect.top)/(window.innerHeight+rect.height)));hero.style.setProperty('--scroll',scrolled);const bg=hero.querySelector('#hero::before,hero::after');const content=hero.querySelector('.hero-content');if(content){content.style.transform=`translateY(${scrolled*30}px)`;content.style.opacity=1-scrolled*0.15}})
